"""
MKT Original — Matthew chapters 23–24
Output: data/commentary/mkt-original/matthew.json (adds ch23-24)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: Per-verse Greek lexical commentary for Matthew 23-24; covers the Seven Woes
#   discourse and the Olivet Discourse. Strictly Greek lexical/syntactic analysis.
# CHANGE? If verse keys change in data/interlinear/matthew.json, update dict keys here.
# VERIFY: Run script; confirm "wrote data/commentary/mkt-original/matthew.json".
#   Then check ch23/24 keys match interlinear counts (39/51).

NEW_DATA = {
  "23": {
    "1": "<p><strong>tote ho Iēsous elālēsen tois ochlois kai tois mathētais autou</strong> — <em>then Jesus spoke to the crowds and to his disciples</em> — <em>Tote</em> (then) marks a decisive shift from controversy dialogues to direct address. The dual audience (crowds <em>kai</em> disciples) is unusual; the woes that follow are public indictment, not private instruction.</p>",
    "2": "<p><strong>epi tēs Mōseōs kathedrās ekathisan</strong> — <em>they sit on Moses’ seat</em> — <em>Kathedra Mōsēos</em> (Moses’ seat) is a physical chair in synagogues representing authoritative succession to the Mosaic teaching office. <em>Ekathisan</em> (aorist: have sat down, have taken their seat) acknowledges the institutional authority. The tension is between legitimate office and corrupt practice.</p>",
    "3": "<p><strong>panta oun hosa ean eipōsin hymin poiēsate kai tēreite</strong> — <em>all therefore whatever they say to you, do and keep</em> — The command is qualified immediately: <em>kata de ta erga autōn mē poieite</em> (but do not do according to their deeds). The problem is not their teaching authority but the hypocrisy of teaching without practicing.</p>",
    "4": "<p><strong>desmeuo usin de phortia barēa kai dysbastakta</strong> — <em>they bind heavy and hard-to-bear burdens</em> — <em>Desmeūō</em> (to bind, bundle up) + <em>phortia</em> (loads, burdens) + <em>barēa kai dysbastakta</em> (heavy and difficult to carry). <em>Tō daktylō̧ de autōn ou thelousin kinēsai auta</em> (but with their finger they are unwilling to move them) — the contrast between imposing and alleviating: they use one finger metaphorically to add load while refusing to lift a finger to help.</p>",
    "5": "<p><strong>platūnousin tā phylaktēria</strong> — <em>they widen the phylacteries</em> — <em>Phylaktēria</em> (phylacteries) = the tefillin boxes worn on head and arm during prayer (from Deut 6:8; 11:18; Ex 13:9,16). Larger boxes signaled greater piety; <em>platūnō</em> (to make broad/wide) criticizes competitive public display. <em>Megalunousin ta kraspeda</em> (enlarge the tassels) = lengthen the tzitzit on the prayer shawl (Num 15:38-39).</p>",
    "6": "<p><strong>philousin de tēn prōtōklisian en tois deipnois</strong> — <em>they love the place of honor at feasts</em> — <em>Prōtōklisia</em> (first-reclining-place, seat of honor) = the couch nearest the host at a formal banquet. <em>Prōtokathedrias en tais synagōgais</em> (chief seats in the synagogues) = the front benches facing the congregation. Both are public-honor markers.</p>",
    "7": "<p><strong>tous aspasmous en tais agorais</strong> — <em>greetings in the marketplaces</em> — Public greetings with the title <em>Rhabbi</em> (my great one, my teacher — from Heb. <em>rab</em> = great) conferred honor before witnesses. <em>Kaleōsthai hypo tōn anthrōpōn Rhabbi</em> (to be called Rabbi by people) — the passive <em>klēthenai</em> (to be called, to be addressed) is the coveted public recognition.</p>",
    "8": "<p><strong>hymeis de mē klēthēte Rhabbi</strong> — <em>but you, do not be called Rabbi</em> — The aorist passive prohibition <em>mē klēthēte</em> is strong. The grounds: <em>heis gar estin hymōn ho didaskālos</em> (for one is your teacher) and <em>pantes de hymeis adelphoi este</em> (and you are all brothers). The community is horizontally structured under one Teacher (<em>didaskalos</em>), not vertically ranked.</p>",
    "9": "<p><strong>kai patera mē kalēsēte hymōn epi tēs gēs</strong> — <em>and call no one your father on the earth</em> — <em>Patēr</em> (father) as a religious title (equivalent to spiritual father/founder of a school); <em>heis gar estin hymōn ho patēr ho ouranios</em> (for one is your Father, the heavenly one). The prohibition targets honorific titling that displaces divine fatherhood, not biological naming.</p>",
    "10": "<p><strong>mēde klēthēte kathēgētai</strong> — <em>nor be called guides/leaders</em> — <em>Kathēgētēs</em> (guide, instructor, leader — a rarer term than <em>didaskalos</em>; used for philosophical and religious teachers who lead others). <em>Heis gar estiñ hymōn ho Kathēgētēs ho Christos</em> (for one is your Guide, the Christ) — Christ as sole authoritative teacher.</p>",
    "11": "<p><strong>ho de meizon hymōn estai hymōn diakonos</strong> — <em>the greater among you shall be your servant</em> — The comparative <em>meizon</em> (greater) picks up the status-vocabulary of the Woes and redirects it: greatness is servant-function (<em>diakonos</em> = table-servant). This repeats the community principle from 20:26-27.</p>",
    "12": "<p><strong>hostis de hypsōsei heauton tapeinōthēsetai</strong> — <em>whoever exalts himself will be humbled</em> — The divine passives (<em>tapeinōthēsetai</em> = will be humbled; <em>hypsōthēsetai</em> = will be exalted) are eschatological reversals enacted by God. The pattern inverts all social-honor logic and is a structuring principle throughout the Sermon and beyond.</p>",
    "13": "<p><strong>ouai de hymin grammateis kai Pharisaioi hypokritai</strong> — <em>woe to you, scribes and Pharisees, hypocrites</em> — <em>Ouai</em> is a lament-curse (not primarily imprecation but prophetic grief over coming judgment). <em>Hoti kleiete tēn basileian tōn ouranōn emprosthen tōn anthrōpōn</em> (because you shut the kingdom of heaven before people) — <em>kleiō</em> (to shut, lock); they neither enter nor permit others entry (<em>tous eiserchotas</em>).</p>",
    "14": "<p><em>[v.14 absent in earliest manuscripts — NA28 omits; a textual insertion parallel to Mark 12:40 / Luke 20:47]</em></p>",
    "15": "<p><strong>periagete tēn thalassan kai tēn xēran poiēsai hena prosēlyton</strong> — <em>you travel the sea and the dry land to make one proselyte</em> — <em>Prosēlytos</em> (proselyte, convert — from <em>prosēlythō</em> = to come to) = a Gentile who fully converted to Judaism including circumcision and immersion. The zeal is acknowledged; the indictment is that the product (<em>huion geennēs</em> = son of Gehenna) ends worse than before: <em>diploteron hymōn</em> (twice as much as yourselves).</p>",
    "16": "<p><strong>hodoi typhloi</strong> — <em>blind guides</em> — <em>Hodos</em> (guide, one who leads on the path) + <em>typhloi</em> (blind) = a self-defeating combination. The Woe focuses on casuistry about oath-binding: swearing by the naos (inner sanctuary) vs. the gold of the naos. Jesus’ critique targets selective oath-binding that creates loopholes in solemn commitments.</p>",
    "17": "<p><strong>mōroi kai typhloi</strong> — <em>fools and blind ones</em> — <em>Mōros</em> (fool, dull, stupid — a rare strong reproach; in 5:22 its use against a brother was condemned) used here by Jesus himself against the scribes in their capacity as false teachers. The rhetorical question: <em>tis gar meizon estin ho chrysos ē ho naos ho hagiasas ton chryson</em> (which is greater, the gold or the sanctuary that sanctified the gold?) inverts the reasoning: the sanctuary confers sanctity on the gold, not vice versa.</p>",
    "18": "<p><strong>hos d’ an omōsē en tō̄ thysiastēriō̧ ouden estin</strong> — <em>whoever swears by the altar is nothing</em> — The same casuistry applied to the altar: swearing by the altar is dismissed as non-binding while swearing by the gift on it is binding. <em>Opheilei</em> (is obligated, owes) = carries legal force. Jesus dismantles the loophole structure entirely.</p>",
    "19": "<p><strong>typhloi</strong> — <em>blind ones</em> — The repetition of <em>typhloi</em> emphasizes the moral blindness underlying the casuistry. <em>Ti gar meizon to dōron ē to thysiastērion to hagiazōn to dōron</em> (for what is greater, the gift or the altar that sanctifies the gift?) — the same logic as v.17: the sanctifying agent is greater than what it sanctifies.</p>",
    "20": "<p><strong>ho oun omōsas en tō̄ thysiastēriō̧ omnuei en autō̧ kai en pasin tois epanō autou</strong> — <em>whoever swears by the altar swears by it and by all things on it</em> — Jesus’ resolution collapses all the casuistic distinctions: swearing by any part of the temple complex implicates the whole and ultimately God himself. The sequence builds through vv.20-22 to the same conclusion: all oaths invoke God.</p>",
    "21": "<p><strong>kai ho omōsas en tō̄ naō̧ omnuei en autō̧ kai en tō̄ katoikounti auton</strong> — <em>and whoever swears by the sanctuary swears by it and by the one dwelling in it</em> — <em>Ho katoikōn</em> (the one who dwells) = God, whose Shekinah presence fills the naos. Every oath by the temple is ultimately an oath by the divine Presence.</p>",
    "22": "<p><strong>kai ho omōsas en tō̄ ouranō̧ omnuei en tō̄ thronō̧ tou theou</strong> — <em>and whoever swears by heaven swears by the throne of God</em> — The final step: swearing by heaven invokes the divine throne. Jesus’ argument (drawing on 5:33-37) shows all oath-distinctions collapse into direct appeal to God; therefore straightforward speech (<em>nai/ou</em>) is required.</p>",
    "24": "<p><strong>hodoi typhloi hoi diyōlizein ton kōnōpa</strong> — <em>blind guides who strain out the gnat</em> — <em>Diűlizō</em> (to strain through, filter) — wine was filtered to remove insects that would make it ritually impure. <em>Kōnōps</em> (gnat, mosquito) = the smallest ritually impure insect; <em>kamēlon de katapinon tes</em> (but swallowing the camel) = the largest land animal. The gnat/camel contrast is extreme comic hyperbole; both are unclean (Lev 11), but the proportions reveal absurd priority inversion.</p>",
    "25": "<p><strong>katharizete to exōthen tou potēriou kai tēs paropsidos</strong> — <em>you cleanse the outside of the cup and dish</em> — <em>Exōthen</em> (outside) vs. <em>esōthen</em> (inside) — the Woe targets ritual purity practice that leaves the interior (<em>gemousin ex harpagēs kai akrasias</em> = full of extortion and self-indulgence) untouched. <em>Harpagē</em> (plunder, extortion) and <em>akrasia</em> (lack of self-control, incontinence) describe the moral contents contrasted with the clean exterior.</p>",
    "26": "<p><strong>Pharisaie typhle katharison prōton to entos tou potēriou</strong> — <em>blind Pharisee, first cleanse the inside of the cup</em> — The singular <em>Pharisaie</em> (Pharisee) shifts from plural address to singular, making the charge personal. <em>Hina genētai kai to ektos autou katharon</em> (so that the outside also becomes clean) — interior purification naturally produces exterior cleanness; the reverse is impossible.</p>",
    "27": "<p><strong>paromoiazete taphois kekoniamenois</strong> — <em>you are like whitewashed tombs</em> — <em>Kekoniamenos</em> (perfect passive participle of <em>koniáō</em> = to whitewash with lime) — tombs were whitewashed before Passover (Nisan) so pilgrims would not inadvertently touch them and incur corpse-impurity. <em>Exōthen men phainontai horaioi</em> (outwardly appear beautiful/clean) — <em>horaios</em> (beautiful, seasonable, timely) contrasts with <em>esōthen de gemousin osteon nekrōn</em> (but inside full of dead men’s bones).</p>",
    "28": "<p><strong>houtos kai hymeis exōthen men phainesthe tois anthrōpois dikaioi</strong> — <em>so you also outwardly appear righteous to people</em> — <em>Phainō</em> (to appear, seem) vs. genuine reality: <em>esōthen de este mestoi hypokriseōs kai anomias</em> (but inside you are full of hypocrisy and lawlessness). <em>Hypokrisis</em> (stage-playing, pretense) and <em>anomia</em> (lawlessness, without-law-ness) are the twin interior conditions behind the righteous facade.</p>",
    "29": "<p><strong>oikodomei te ta mnēmeia tōn prophētōn</strong> — <em>you build the tombs of the prophets</em> — The final Woe targets the self-deceiving claim that the current generation would not have killed the prophets as their ancestors did (<em>legete: ei ēmetha en tais hēmerais tōn paterōn hēmōn</em>). The tomb-building is presented as a claim to discontinuity with the murderous past.</p>",
    "30": "<p><strong>ouk an ēmetha koinōnoi autōn</strong> — <em>we would not have been partners with them</em> — <em>Koinōnōs</em> (partner, sharer, participant) in the blood of the prophets. The second-class conditional (<em>ei ēmetha... ouk an ēmetha</em>) expresses a counterfactual, but Jesus’ response (v.31-32) shows their claim is self-indicting.</p>",
    "31": "<p><strong>hoste martyreite heautois hoti huioi este tōn phoneusāntōn tous prophētas</strong> — <em>so you witness against yourselves that you are sons of those who murdered the prophets</em> — <em>Martyreite heautois</em> (you testify against yourselves) — their own admission of ancestry is the self-incriminating testimony. <em>Huioi</em> (sons) here = those who continue the character/pattern, not merely biological descendants.</p>",
    "32": "<p><strong>kai hymeis plērōsate to metron tōn paterōn hymōn</strong> — <em>and you fill up the measure of your fathers</em> — <em>Plērōsate</em> (aorist imperative or prophetic aorist: fill up completely) — <em>metron</em> (measure) = the fixed capacity that must be reached before judgment falls (cf. Gen 15:16; 1 Thess 2:16). Jesus speaks as if the murder of himself is the act that completes the measure.</p>",
    "33": "<p><strong>opheis genēmata echidnōn</strong> — <em>serpents, brood of vipers</em> — The same epithet John the Baptist applied to Pharisees (3:7; 12:34). <em>Pōs phygēte apo tēs kriseōs tēs geennēs</em> (how will you flee from the judgment of Gehenna?) — <em>kriseos</em> (genitive of <em>krisis</em>) + <em>geenna</em> (Gehenna = Valley of Hinnom, the place of eschatological fire).</p>",
    "34": "<p><strong>prophētas kai sophous kai grammateis</strong> — <em>prophets and wise ones and scribes</em> — Jesus sends these emissaries (<em>apōstellō</em> = I send; first-person: Jesus himself sends, in divine authority). Three fates: <em>apokteneite</em> (kill), <em>staurosete</em> (crucify), <em>mastigōsete</em> (flog), <em>diōxete</em> (persecute) — the full range of violence against Christian missionaries anticipated.</p>",
    "35": "<p><strong>haimatos dikaiou ekchynnomenou epi tēs gēs</strong> — <em>righteous blood shed upon the earth</em> — From <em>Habel tou dikaiou</em> (Abel the righteous, Gen 4:8) to <em>Zachariou huiou Barachious</em> (Zechariah son of Barachiah) — the canonical span from Genesis to 2 Chronicles (the last book in the Hebrew canon). <em>Ekchynnomenon</em> (being poured out, present passive participle) keeps the spilled blood as ongoing cry before God.</p>",
    "36": "<p><strong>hēxei tauta panta epi tēn genean tautēn</strong> — <em>all these things will come upon this generation</em> — <em>Genea autē</em> (this generation) throughout Matthew’s Passion block refers to the contemporaries of Jesus; the fulfillment in AD 70 is the historical horizon. <em>Hēxei</em> (future: will come) is a judicial visitation term.</p>",
    "37": "<p><strong>Iērousalom Iērousalom hē apokteinousa tous prophētas</strong> — <em>Jerusalem, Jerusalem, the one killing the prophets</em> — The doubled vocative (<em>Iērousalom Iērousalom</em>) is a lament formula (cf. 2 Sam 18:33; LXX repeated vocative as grief). <em>Pōsákis ēthelēsa episynagagein ta tekna sou</em> (how often I wished to gather your children) — <em>episynagō</em> (gather together) + <em>hōs ornis episynagei tā nossia heautēs</em> (as a hen gathers her chicks under her wings) — a maternal image of divine protection-longing.</p>",
    "38": "<p><strong>idou aphietai hymin ho oikos hymōn eremos</strong> — <em>behold your house is left to you desolate</em> — <em>Ho oikos</em> (the house) = the temple; <em>eremos</em> (desolate, abandoned) echoes the Shekinah’s departure in Ezek 10-11. The divine <em>aphietai</em> (is left, abandoned — present passive) implies God’s withdrawal from the temple.</p>",
    "39": "<p><strong>ou mē me idēte ap’ arti heōs an eipēte</strong> — <em>you will by no means see me from now until you say</em> — <em>Ou mē</em> + aorist subjunctive = the strongest Greek negation. <em>Eulogēmenos ho erchomenos en onomati kyriou</em> (blessed is the coming one in the name of the Lord) = Ps 118:26, the same acclamation from the Triumphal Entry (21:9); the future return will be greeted with the same words, but then as recognition.</p>"
  },
  "24": {
    "1": "<p><strong>eporeueto apo tou hierou</strong> — <em>was going away from the temple</em> — <em>Poreuomai</em> (imperfect: was going away) signals a definitive departure from the temple. <em>Prosēlthon hoi mathētai autou epideixai autō̧ tās oikodomās tou hierou</em> (the disciples came to point out the buildings of the temple) — <em>oikodomās</em> (buildings, constructions) in the plural refers to the entire temple complex.</p>",
    "2": "<p><strong>ou mē aphethē̄ ōde lithos epi lithon</strong> — <em>there will by no means be left here stone upon stone</em> — <em>Ou mē</em> + aorist passive subjunctive = absolute negation of any remaining structure. <em>Hos ou kataly thēsetai</em> (that will not be thrown down) — <em>katalyō</em> (to loosen down, demolish) is used both literally for building-destruction and metaphorically (26:61; 27:40). Fulfilled in AD 70 under Titus.</p>",
    "3": "<p><strong>tis hē sēmeia tēs sēs parousias kai synteleiās tou aiōnos</strong> — <em>what is the sign of your presence/coming and of the completion of the age?</em> — <em>Parousia</em> (presence, arrival — used for royal/imperial visits) is the technical NT term for the Second Advent. <em>Synteleias tou aiōnos</em> (completion/end of the age) — <em>synteleia</em> is consummation, bringing to full end; <em>tou aiōnos</em> = of the age/era.</p>",
    "4": "<p><strong>blepete mē tis hymas planēsē̄</strong> — <em>see to it that no one leads you astray</em> — <em>Planāō</em> (to cause to wander, to mislead) is the eschatological deception verb; it recurs in vv.5, 11, 24. The primary danger is not persecution but deception — being misled about the identity of the Christ and the timing of the end.</p>",
    "5": "<p><strong>polloi gar eleusontai epi tō̄ onomati mou legontes egō eimi ho christos</strong> — <em>for many will come in my name saying I am the Christ</em> — <em>Epi tō̄ onomati mou</em> (in/on my name) = using the authority of the name of Jesus as their credential. <em>Egō eimi ho christos</em> (I am the Christ) — the false messiah claim. <em>Pollōs planēsousin</em> (they will lead many astray) — the deception’s scope is wide.</p>",
    "6": "<p><strong>mellēsete de akouein polemos kai akoai polemōn</strong> — <em>you will hear of wars and rumors of wars</em> — <em>Akoai polemōn</em> (reports/rumors of wars) — the hearing of distant conflicts. <em>Horāte mē throeisthe</em> (see that you are not alarmed) — <em>throeō</em> (to cry out in alarm, to be disturbed) — these are conditions not to be interpreted as the end: <em>all’ oupo estin to telos</em> (but the end is not yet).</p>",
    "7": "<p><strong>egerthēsetai gar ethnos epi ethnos kai basileia epi basileian</strong> — <em>for nation will rise against nation and kingdom against kingdom</em> — The double <em>epi</em> (against) construction with repetition is a LXX war-oracle pattern (Isa 19:2; 2 Chr 15:6). <em>Loimoi kai seismoi kata topous</em> (plagues and earthquakes in various places) — <em>kata topous</em> (in various/diverse places) limits the scope: localized, not final.</p>",
    "8": "<p><strong>panta de tauta archē ōdinōn</strong> — <em>all these are the beginning of birth pangs</em> — <em>Ōdines</em> (birth pains, labor pangs) is an OT apocalyptic metaphor for the distresses preceding the Messianic age (Isa 26:17; Jer 22:23; Mic 4:9-10; 1QH). <em>Archē</em> (beginning) positions these events as the onset of a process, not the culmination.</p>",
    "9": "<p><strong>tote paradosousin hymas eis thlipsin</strong> — <em>then they will hand you over into tribulation</em> — <em>Paradidōmi</em> (to hand over, the passion vocabulary) is now applied to disciples. <em>Thlipsis</em> (tribulation, pressure, affliction) — the same word used for the great tribulation in v.21. <em>Apoktenousin hymas</em> (will kill you) — direct persecution. <em>Misounōmenoi hypo pantōn tōn ethnōn</em> (hated by all the nations) — universal hostility.</p>",
    "10": "<p><strong>kai tote skandalisthēsontai polloi</strong> — <em>and then many will fall away</em> — <em>Skandalizō</em> (to cause to stumble, to cause to fall away) — the passive future: many will be caused to stumble from faith. <em>Allēlous paradosousin</em> (they will betray one another) — communal breakdown; persecution produces internal betrayal. <em>Misēsousin allēlous</em> (will hate one another).</p>",
    "11": "<p><strong>polloi pseudoprophetai egerthesontai</strong> — <em>many false prophets will arise</em> — <em>Pseudoprophētēs</em> (false prophet) — one who claims prophetic authority falsely. <em>Planēsousin pollous</em> (will lead many astray) — the deception vocabulary recurs (cf. v.4,5). The false prophets operate within the community, not merely from outside.</p>",
    "12": "<p><strong>dia to plēthyn thēnai tēn anomian psēgēsetai hē agapē tōn pollōn</strong> — <em>because of the increase of lawlessness the love of many will grow cold</em> — <em>Anomīa</em> (lawlessness) as cause; <em>psúchō</em> (to cool down, grow cold) as effect on <em>agapē</em> (love). The causal connection: sustained exposure to ethical collapse erodes love. <em>Tōn pollōn</em> = of the many (the majority), not universally.</p>",
    "13": "<p><strong>ho de hypominās eis telos houtos sōthēsetai</strong> — <em>but the one who endures to the end will be saved</em> — <em>Hypominō</em> (to remain under, to endure — not passive resignation but active steadfastness under pressure). <em>Eis telos</em> (to the end) — whether the end of one’s life or the end of the age. <em>Sōthēsetai</em> (will be saved) future passive = eschatological salvation.</p>",
    "14": "<p><strong>kērych thēsetai touto to euangelion tēs basileias en holȩ̄ tē̄ oikoumenē̄</strong> — <em>this gospel of the kingdom will be proclaimed in all the inhabited world</em> — <em>Oikoumenē</em> (the inhabited world — the Greek term for the civilized/Roman world) is here given universal scope. <em>Eis martyrion pasin tois ethnesin</em> (as a testimony to all the nations) — <em>martyrion</em> (witness, testimony, evidence). <em>Kai tote hēxei to telos</em> (and then the end will come) — the gospel-to-all-nations is a precondition for the end.</p>",
    "15": "<p><strong>to bdelygma tēs erēmōseōs</strong> — <em>the abomination of desolation</em> — <em>Bdelygma</em> (abomination — from <em>bdelyssōmai</em> = to be disgusted by, to abhor) is the LXX term for idolatrous desecration (Dan 9:27; 11:31; 12:11 LXX). <em>Hestōs en topō̧ hagiō̧</em> (standing in a holy place) — the masculine participle <em>hestōs</em> with the neuter noun <em>bdelygma</em> may suggest a person (antichrist figure) rather than an object. <em>Ho anaginnōskōn noeitō</em> (let the reader understand) is a direct address to the reader of the written prophecy.</p>",
    "16": "<p><strong>tote hoi en tē̄ Ioudaiā̧ pheugetōsan eis ta orē</strong> — <em>then let those in Judea flee to the mountains</em> — <em>Pheugetōsan</em> (present imperative 3rd plural: let them flee, keep fleeing) — urgency of continuous flight. The command applies to those in Judea specifically, not universally; the geographical specificity supports a first-century Jerusalem referent.</p>",
    "17": "<p><strong>ho epi tou dōmatos mē katabatō</strong> — <em>let the one on the rooftop not come down</em> — Palestinian flat-roofed houses had exterior stairs; one could flee directly from rooftop to street without entering the house to gather possessions. <em>Ârai ta ek tēs oikias autou</strong> (to take the things from his house) — the urgency of escape outweighs property retrieval.</p>",
    "18": "<p><strong>kai ho en tō̄ agrō̧ mē epistrepsatō opisō</strong> — <em>and the one in the field, let him not turn back</em> — <em>Epistrepho</em> (to turn back, return) — a worker in the field should not return home for his cloak (<em>himation</em>). The same urgency governs both rooftop and field scenarios.</p>",
    "19": "<p><strong>ouai de tais en gastri echousais kai tais thēlazousais</strong> — <em>woe to those who are pregnant and to those nursing</em> — <em>Ouai</em> here is genuine lamentation over physical vulnerability in flight: pregnant women and nursing mothers cannot flee quickly. The <em>ouai</em> is compassionate, not judicial.</p>",
    "20": "<p><strong>proseuchesthe de hina mē genētai hē phygē hymōn cheimonos mēde sabbatō̧</strong> — <em>pray that your flight not happen in winter nor on a Sabbath</em> — Winter flight is physically dangerous (flooding wadis, cold). Sabbath flight raises a Jewish law issue: travel beyond the Sabbath limit (<em>techum Shabbat</em> = ~2000 cubits) is prohibited; a Sabbath escape would force a choice between legal observance and survival. The prayer assumes continued Sabbath observance in the community.</p>",
    "21": "<p><strong>estai gar tote thlipsis megalē hoia ou gegonen ap’ archēs kosmou</strong> — <em>for then there will be great tribulation such as has not been from the beginning of the world</em> — <em>Thlipsis megalē</em> (great tribulation) — the decisive eschatological crisis. The comparison formula <em>hoia ou gegonen</em> (such as has not been) echoes Dan 12:1 LXX. The phrase <em>heōs tou nyn</em> (until now) + <em>oud’ ou mē genētai</em> (nor will ever be) brackets the event as uniquely catastrophic.</p>",
    "22": "<p><strong>ei mē ekolobōthēsan hai hēmerai ekeinai ouk an esōthē pasa sarx</strong> — <em>if those days had not been cut short, no flesh would be saved</em> — <em>Koloboō</em> (to cut short, to mutilate by cutting off — from <em>kolobos</em> = maimed) — the shortening is divine mercy. <em>Pasa sarx</em> (all flesh) = all living humans. <em>Dia de tous eklektous</em> (but for the sake of the elect) — the elect’s preservation motivates the divine shortening of tribulation.</p>",
    "23": "<p><strong>tote ean tis hymin eipē̄ idou hōde ho christos ē hōde</strong> — <em>then if anyone says to you: here is the Christ, or here!</em> — The repeated warning against false location-claims for the Christ (vv.23-26) uses <em>idou hōde... ē hōde</em> (here... or there) to characterize false messiahs as geographically bounded. <em>Mē pisteusēte</em> (do not believe) — aorist subjunctive prohibition.</p>",
    "24": "<p><strong>egerthēsontai gar pseudochristoi kai pseudoprophetai</strong> — <em>for false christs and false prophets will arise</em> — <em>Pseudochristos</em> (false christ, counterfeit anointed one) and <em>pseudoprophētēs</em> (false prophet) are paired. <em>Dōsousin sēmeia megala kai terata</em> (will give great signs and wonders) — the deception’s power is real; the signs are genuine miracles. <em>Hōste planēsai ei dynaton kai tous eklektous</em> (so as to lead astray, if possible, even the elect) — <em>ei dynaton</em> (if possible) — the elect cannot ultimately be permanently deceived, but the attempt is real.</p>",
    "25": "<p><strong>idou proeireka hymin</strong> — <em>behold I have told you beforehand</em> — <em>Prolegō</em> (to say beforehand, to forewarn) perfect active: the warning is completed and stands on record. The pre-announcement serves as authentication when the events occur and as inoculation against surprise.</p>",
    "26": "<p><strong>ean oun eipōsin hymin idou en tē̄ erēmō̄ estin mē exelthēte</strong> — <em>if therefore they say: he is in the wilderness, do not go out</em> — Two false-location scenarios: wilderness (<em>erēmos</em> — where messianic movements gathered, cf. Acts 21:38) and inner rooms (<em>tameiois</em> — secret, hidden location). Both are rejected: the true Parousia will not be localized or secret.</p>",
    "27": "<p><strong>hōsper gar hē astrapē exerchetai apo anatolōn</strong> — <em>for as the lightning comes from the east</em> — <em>Astrapē</em> (lightning flash) + <em>phainetai heōs dysmōn</em> (shines to the west) — lightning is universally visible, not localized. The Parousia of the Son of Man will be similarly visible to all simultaneously, requiring no one to point it out. <em>Houtōs estai hē parousia tou huiou tou anthrōpou</em> — the comparison is precise.</p>",
    "28": "<p><strong>hopou ean ȩ̄ to ptōma ekei synachthēsontai hoi aetoi</strong> — <em>wherever the corpse is there the eagles will be gathered</em> — <em>Ptōma</em> (fallen body, corpse) and <em>aetoi</em> (eagles or vultures; in Palestine, likely griffon vultures that are drawn to carrion from great distances). The proverb may signal that judgment follows its object as inevitably as scavengers find a carcass, or that the Parousia (like lightning v.27) is unmistakably obvious when it comes.</p>",
    "29": "<p><strong>eutheos de meta tēn thlipsin tōn hēmerōn ekeinōn</strong> — <em>immediately after the tribulation of those days</em> — <em>Eutheōs</em> (immediately, at once) connects the cosmic signs directly to the tribulation. <em>Ho hēlios skotisthēsetai</em> (the sun will be darkened) — cosmic de-creation language from Isa 13:10 (Babylon oracle) and Joel 2:10,31; 3:15. The powers of the heavens being shaken (<em>hai dynameis tōn ouranōn saleuthhsontai</em>) echoes Isa 34:4 and Hag 2:6,21.</p>",
    "31": "<p><strong>apostelei tous angelous autou meta sal pignos megalēs phōnēs</strong> — <em>he will send his angels with a great trumpet sound</em> — <em>Salpi nx megalē</em> (great trumpet) echoes Isa 27:13 (the great trumpet gathering the scattered of Israel) and the Shofar Gadol of Jewish eschatology. <em>Episynaxousin tous eklektous autou</em> (will gather together his elect) — <em>episynagō</em> (to gather together to oneself) from <em>ek tōn tessarōn anemōn</em> (from the four winds) = universal gathering from every direction.</p>",
    "32": "<p><strong>apo de tēs sykēs mathete tēn parabolēn</strong> — <em>from the fig tree learn the parable</em> — <em>Mathete</em> (learn, aorist imperative from <em>manthanō</em>) the lesson that nature teaches. <em>Hotan ēdē ho klados autēs genētai hapalos</em> (when already its branch becomes tender) — <em>hapalos</em> (tender, soft) of fresh spring growth. The fig tree’s budding is a natural sign that summer (<em>theros</em>) is near; the eschatological signs similarly indicate nearness.</p>",
    "33": "<p><strong>ginos kete hoti eggys estin epi thyrais</strong> — <em>know that it is near, at the doors</em> — <em>Eggys</em> (near, close) + <em>epi thyrais</em> (at the doors) = immediacy idiom for imminent arrival. The subject is ambiguous: the end, or the Son of Man; the ambiguity is probably intentional.</p>",
    "34": "<p><strong>ou mē parelthu hē genea autē</strong> — <em>this generation will by no means pass away</em> — <em>Ou mē</em> + aorist subjunctive = strongest negation. <em>Genea autē</em> (this generation) is the key exegetical question: Jesus’ contemporaries (first-century fulfillment in AD 70 for the near horizon) or the generation that sees the end-time signs (far-horizon reading). The double referent allows both readings.</p>",
    "35": "<p><strong>ho ouranos kai hē gē pareleusontai hoi de logoi mou ou mē parelthōsin</strong> — <em>heaven and earth will pass away but my words will by no means pass away</em> — The contrast between cosmic impermanence (<em>pareleusontai</em> = will pass away, future indicative) and the permanence of Jesus’ words (<em>ou mē parelthōsin</em> = will by no means pass away) is a Christological claim: Jesus’ word has greater ontological stability than creation itself.</p>",
    "36": "<p><strong>peri de tēs hēmeras ekeinēs kai hōras oudeis oiden</strong> — <em>but concerning that day and hour no one knows</em> — <em>Oudeis oiden</em> (no one knows) — absolute ignorance across all categories: <em>oude hoi angeloi tōn ouranōn</em> (not even the angels of heaven) and <em>oude ho huios</em> (not even the Son — present in some MSS, absent in others; Matthean text-critical debate). <em>Ei mē ho patēr monos</em> (except the Father alone).</p>",
    "37": "<p><strong>hōsper gar ai hēmerai tou Nōe houtōs estai hē parousia</strong> — <em>for as the days of Noah so will be the Parousia</em> — The Noah analogy emphasizes normalcy and surprise: <em>trogontes kai pinontes</em> (eating and drinking), <em>gamoyntes kai gamizonte s</em> (marrying and giving in marriage) — ordinary life, not eschatological alertness. <em>Heōs hēs ēmeras eisēlthen Nōe eis tēn kibōton</em> (until the day Noah entered the ark).</p>",
    "38": "<p><strong>ēsan gar en tais hēmerais ekeinais priston tou kataklysmou trogontes kai pinontes</strong> — <em>for in those days before the flood they were eating and drinking</em> — <em>Kataklysmos</em> (flood, inundation — from <em>kataklyzo</em> = to flood over) is the standard Greek term for the Noahic flood. <em>Priston tou kataklysm ou</em> (before the flood) — the total unawareness despite Noah’s preaching.</p>",
    "39": "<p><strong>kai ouk egnosan hōs ēlthen ho kataklysmos</strong> — <em>and they did not know until the flood came</em> — <em>Ouk egnōsan</em> (did not know) — deliberate ignorance or culpable inattention; the flood’s arrival (<em>ēlthen</em>) broke their normalcy without warning. <em>Kai ēren hapantas</em> (and took them all away) — <em>airō</em> (to lift up, take away) in the judgment sense. <em>Houtōs estai kai hē parousia tou huiou tou anthrōpou</em> (so will be the Parousia of the Son of Man).</p>",
    "40": "<p><strong>tote duo esontai en tō̄ agrō̧</strong> — <em>then two will be in the field</em> — The paired-person scenarios (field, mill) show that identical external situations will have opposite outcomes. <em>Heis paralam bānetai kai heis aphietai</em> (one is taken and one is left) — <em>paralambanō</em> (to take alongside, to receive) vs. <em>aphiēmi</em> (to leave behind, dismiss) — the direction of the verbs suggests the taken one is received/saved and the left one is abandoned to judgment (though interpretations vary).</p>",
    "41": "<p><strong>dyo alēthousai en tō̄ mylōni</strong> — <em>two women grinding at the mill</em> — <em>Alēthō</em> (to grind grain) + <em>mylos</em> (mill, millstone) — domestic labor, typically women’s work. The same division: <em>mia paralambanetai kai mia aphietai</em> (one is taken and one is left). The separation occurs within ordinary domestic life, not during extraordinary circumstances.</p>",
    "42": "<p><strong>grēgoreite oun hoti ouk oidate poiā hēmera ho kyrios hymōn erchetai</strong> — <em>watch therefore because you do not know on what day your Lord comes</em> — <em>Grēgoreō</em> (to be awake, be alert, watch — from <em>egerthēnai</em> = to arise from sleep) is the eschatological watchword. The ignorance of the day (<em>ouk oidate</em>) motivates continuous vigilance, not passive waiting.</p>",
    "43": "<p><strong>ekeino de ginōskete hoti ei ē̄dei ho oikodespotēs</strong> — <em>but know this: if the householder had known</em> — <em>Oikodespotēs</em> (householder, master of the house) is used in a second-class conditional (<em>ei + aorist indicative... an + aorist indicative</em>) = contrary to fact: he did not know, so he was robbed. <em>Poia phylakē̄ ho klēptēs erchetai</em> (what watch the thief comes) — the night was divided into four watches (Roman system).</p>",
    "44": "<p><strong>dia touto kai hymeis ginesthe heti moi hoi</strong> — <em>therefore you also be ready</em> — <em>Ginesthe h etoimoi</em> (present imperative: keep being ready) — ongoing state of preparedness, not a one-time act. <em>Hō̄ ou dokei ōra</em> (at an hour you do not expect) — the unexpected hour is the precise one that comes; expectation does not determine timing.</p>",
    "45": "<p><strong>tis ara estin ho pistos doulos kai phronimos</strong> — <em>who then is the faithful and wise servant?</em> — The parable of the faithful and wicked servants interprets eschatological watchfulness through the figure of a household steward. <em>Pistos kai phronimos</em> (faithful and wise) — the pairing of reliability and practical wisdom. <em>Epi tēs oiketeias autou</em> (over his household) — <em>oiketeia</em> (household, domestic staff) — the steward’s responsibility is the whole household’s provision.</p>",
    "46": "<p><strong>makarios ho doulos ekeinos hon elthōn ho kyrios autou heurēsei houtōs poiounta</strong> — <em>blessed is that servant whom his lord when he comes will find so doing</em> — <em>Makārios</em> (blessed — the Beatitude word) applied to the faithful servant found at work on the master’s return. <em>Poiounta</em> (present participle: doing, actively engaged) — not waiting passively but actively serving.</p>",
    "47": "<p><strong>epi pasin tois hyparchousin autou katastesei auton</strong> — <em>over all his possessions he will appoint him</em> — <em>Kath istēmi</em> (to appoint, install, set in place) — the faithful steward’s reward is expanded responsibility, not retirement. <em>Epi pasin tois hyparchousin</em> (over all his possessions) = complete estate management.</p>",
    "48": "<p><strong>ean de eipē̄ ho kakos doulos ekeinos</strong> — <em>but if that wicked servant says</em> — The third-class conditional (<em>ean</em> + aorist subjunctive) presents the wicked servant’s reasoning as possible, not certain. <em>Chronizei mou ho kyrios</em> (my master is delayed) — <em>chronizō</em> (to take time, delay, be a long time) — the delay itself becomes the rationalization for misconduct.</p>",
    "49": "<p><strong>arxētai de typtein tous syndoulous autou</strong> — <em>he begins to beat his fellow servants</em> — <em>Syndoūlos</em> (fellow servant, co-slave) — the wicked servant exploits those under him while the master is absent. <em>Esthī̄ de kai pinē̄ meta tōn methyontōn</em> (and eats and drinks with the drunk ones) — self-indulgence and violent domination are paired as the twin abuses of delegated authority.</p>",
    "50": "<p><strong>hēxei ho kyrios tou doulou ekeinou en hēmera h̄ ou prosdokā̄</strong> — <em>the master of that servant will come on a day he does not expect</em> — <em>Hēxei</em> (will come, future indicative of <em>hēkō</em> = to have arrived, to be present) — the arrival is certain; only the timing is unknown. The doubled <em>ou prosdokā̄</em> (does not expect) + <em>en hōrā̄ ou ginōskei</em> (at an hour he does not know) emphasizes complete unpreparedness.</p>",
    "51": "<p><strong>dichotomēsei auton kai to meros autou meta tōn hypokritōn thēsei</strong> — <em>he will cut him in two and put his portion with the hypocrites</em> — <em>Dichotomēsei</em> (to cut in two, to bisect — from <em>dicha</em> = in two + <em>temnō</em> = to cut) is a brutal image of complete destruction/dismemberment used for execution. <em>Meta tōn hypokritōn</em> (with the hypocrites) — the final category for the unfaithful steward. <em>Ho klauthmos kai ho brygmos tōn odontōn</em> recurs as the judgment formula.</p>"
  }
}

comm = load_comm('mkt-original', 'matthew')
merge_comm(comm, NEW_DATA)
save_comm('mkt-original', 'matthew', comm)

